import numpy as np

def naive_bayes_predict(log_prior, log_likelihood, doc_tokens):
    class_scores = log_prior.copy()
    for t in doc_tokens:
        if t in log_likelihood:
            class_scores += log_likelihood[t]
    return class_scores

if __name__ == '__main__':
    print('Naive Bayes prediction framework initialized.')
